var e=[{id:`L5_1`,type:`dialog`,speaker:`AGENT_GRONIA_WHITE_NAME`,text:{KOREA:`바이크를 쫓아오다니 제법인걸?`,JPN:`バイクのスピードに追いつくとはやるね。`,ENG:`I'm impressed you're able to catch up when I'm on my bike.`,TWN:`竟然追上來了，不錯喔？`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_SERIOUS`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`HARVESTER_NPC_NULL_NULL`,text:{KOREA:`못 도망친다.`,JPN:`逃ガサナイ。`,ENG:`You cannot run away.`,TWN:`你逃不了的。`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`HARVESTER_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`HARVESTER_NPC_NULL_NULL`,text:{KOREA:`시간… 낭비일 뿐.`,JPN:`時間ノ……無駄ダ。`,ENG:`Waste... of time.`,TWN:`只是浪費時間而已……`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`HARVESTER_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L9_1`,type:`dialog`,speaker:`AGENT_GRONIA_WHITE_NAME`,text:{KOREA:`시간? 침식체가 재미있는 단어를 쓰네.`,JPN:`時間？　侵食体のくせに、面白い単語を使うね。`,ENG:`Time? Funny hearing that word coming from a C.O.`,TWN:`時間？侵蝕體竟然也會說這種詞？`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_IDLE`},C:null,R:{char_id:`HARVESTER_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`AGENT_GRONIA_WHITE_NAME`,text:{KOREA:`그럼 수류탄이란 것도 들어 봤어?`,JPN:`じゃあ、手榴弾っていう言葉も知ってるのかな？`,ENG:`Then, have you ever heard of the words, "hand grenade?"`,TWN:`那你聽說過手榴彈嗎？`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`HARVESTER_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`HARVESTER_NPC_NULL_NULL`,text:{KOREA:`…!`,JPN:`……！`,ENG:`...!`,TWN:`……！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_SERIOUS`},C:null,R:{char_id:`HARVESTER_NPC_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L15_1`,type:`dialog`,speaker:`AGENT_GRONIA_WHITE_NAME`,text:{KOREA:`하, 아슬아슬했군. 거의 따라 잡힐 뻔했어.`,JPN:`はぁ、ぎりぎりだった。もうすこしで追いつかれるところだったよ。`,ENG:`*Sigh.* That was a close one. He almost got me.`,TWN:`哈，好險，差點就被你抓住了。`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_SERIOUS`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`AGENT_GRONIA_WHITE_NAME`,text:{KOREA:`…통신기는 여기서도 먹통인가?`,JPN:`……通信機はここでも使えないのかな？`,ENG:`...Are the comms down here too?`,TWN:`……通訊器又失靈了嗎？`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_HATE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`AGENT_GRONIA_WHITE_NAME`,text:{KOREA:`큭…?!`,JPN:`くっ……！？`,ENG:`Kgh...?!`,TWN:`呃……？！`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_HATE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`AGENT_GRONIA_WHITE_NAME`,text:{KOREA:`침식체가 매복이라고?`,JPN:`侵食体が待ち伏せだと？`,ENG:`A C.O. ambush?!`,TWN:`侵蝕體竟然會埋伏？`},stage:{bg:`COUNTERSIDE_SNOW`,slots:{L:null,C:{char_id:`AGENT_GRONIA_WHITE_NAME`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`하아… 정말.`,JPN:`はあ……まったく。`,ENG:`*Sigh...* Really?`,TWN:`呼……真是的。`},stage:{bg:`SNOWYARD_01`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`바람 쐰다더니 얼마나 멀리 간 거야?`,JPN:`息抜きにどこまで行ったんだ？`,ENG:`How far did she go to get fresh air?`,TWN:`不是說要去透透氣嗎？是跑多遠？`},stage:{bg:`SNOWYARD_01`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`그래, 크리스. 소리에 집중해보자… 집중…`,JPN:`そうよ、クリス。音に集中して……集中……`,ENG:`Okay, Chris. Focus on the sounds... Focus...`,TWN:`好了，克莉絲。注意聽聲音……專注……`},stage:{bg:`SNOWYARD_01`,slots:{L:null,C:{char_id:`ROOKIE_GRONIA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L29_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`으음…`,JPN:`うーん……`,ENG:`Mm...`,TWN:`唔……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L30_1`,type:`dialog`,speaker:`ROOKIE_GRONIA_NULL_NULL`,text:{KOREA:`이건… 희미한 모터 소리…?`,JPN:`これは……微かに聞こえる、モーターの音……？`,ENG:`That's... a faint motor sound...?`,TWN:`那是……微弱的引擎聲……？`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}}];export{e as default};